workflow-item.script:
// Create NSX segment for web tier
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var webSegment = nsxClient.createSegment({
  displayName: "Web-Tier-VLAN100",
  vlanIds: [100],
  subnets: ["10.10.100.0/24"],
  gateway: "10.10.100.1",
  description: "Web tier network segment"
});

System.log("Created web tier segment: " + webSegment.id);

// Create NSX segment for app tier
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var appSegment = nsxClient.createSegment({
  displayName: "App-Tier-VLAN150",
  vlanIds: [150],
  subnets: ["10.10.150.0/24"],
  gateway: "10.10.150.1",
  description: "Application tier network segment"
});

System.log("Created app tier segment: " + appSegment.id);

// Create NSX segment for database tier
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var dbSegment = nsxClient.createSegment({
  displayName: "DB-Tier-VLAN200",
  vlanIds: [200],
  subnets: ["10.10.200.0/24"],
  gateway: "10.10.200.1",
  description: "Database tier network segment"
});

System.log("Created database tier segment: " + dbSegment.id);

// Create firewall rule allowing web tier to app tier
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var webToAppRule = nsxClient.createFirewallRule({
  name: "Allow-Web-to-App",
  segment: "Web-Tier-VLAN100",
  sources: ["web-security-group"],
  destinations: ["app-security-group"],
  services: ["HTTP", "HTTPS"],
  action: "ALLOW",
  description: "Allow web tier to communicate with app tier on HTTP/HTTPS"
});

System.log("Created firewall rule: " + webToAppRule.id);

// Create firewall rule allowing app tier to database tier
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var appToDbRule = nsxClient.createFirewallRule({
  name: "Allow-App-to-DB",
  segment: "App-Tier-VLAN150",
  sources: ["app-security-group"],
  destinations: ["db-security-group"],
  services: ["MySQL"],
  action: "ALLOW",
  destination: "10.10.200.50",
  description: "Allow app tier to access database on MySQL port"
});

System.log("Created firewall rule: " + appToDbRule.id);

// Create firewall rule for database backups
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var dbBackupRule = nsxClient.createFirewallRule({
  name: "Allow-DB-Backup",
  segment: "DB-Tier-VLAN200",
  vlan: 200,
  sources: ["backup-server"],
  destinations: ["db-security-group"],
  destination: "10.10.200.50",
  services: ["SSH"],
  action: "ALLOW",
  description: "Allow backup server to access database for backups"
});

System.log("Created firewall rule: " + dbBackupRule.id);

// Create general internet egress rule (no specific segment)
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var internetEgressRule = nsxClient.createFirewallRule({
  name: "Allow-Internet-Egress",
  sources: ["any"],
  destinations: ["internet"],
  services: ["HTTP", "HTTPS"],
  action: "ALLOW",
  description: "Allow all tiers to access internet for updates"
});

System.log("Created firewall rule: " + internetEgressRule.id);

// Create DNS rule (no specific segment)
var nsxClient = System.getModule("com.acme.nsx").getNSXClient();

var dnsRule = nsxClient.createFirewallRule({
  name: "Allow-DNS",
  sources: ["any"],
  destinations: ["dns-servers"],
  services: ["DNS"],
  action: "ALLOW",
  description: "Allow DNS queries from all networks"
});

System.log("Created firewall rule: " + dnsRule.id);
success = true;
